use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}

fn filter_above_threshold(d: dict.Dict<ByteArray, Int>, threshold: Int) -> dict.Dict<ByteArray, Int> {
  dict.filter(d, fn(_k, v) { v > threshold })
}

fn count_qualifying(d: dict.Dict<ByteArray, Int>, threshold: Int) -> Int {
  dict.size(filter_above_threshold(d, threshold))
}

validator spend_balance_filter {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let balances = dict.empty
      |> dict.insert(#"aabb", 500)
      |> dict.insert(#"ccdd", 100)
      |> dict.insert(#"eeff", 1000)
    count_qualifying(balances, 200) >= 2
  }
}

test filter_above_threshold_basic() {
  let d = dict.empty
    |> dict.insert(#"01", 10)
    |> dict.insert(#"02", 50)
    |> dict.insert(#"03", 5)
  let filtered = filter_above_threshold(d, 8)
  dict.size(filtered) == 2
}

test filter_above_threshold_none_qualify() {
  let d = dict.empty
    |> dict.insert(#"aa", 1)
    |> dict.insert(#"bb", 2)
  dict.size(filter_above_threshold(d, 100)) == 0
}

test count_qualifying_all() {
  let d = dict.empty
    |> dict.insert(#"aa", 99)
    |> dict.insert(#"bb", 100)
  count_qualifying(d, 50) == 2
}

test filter_preserves_value() {
  let d = dict.empty
    |> dict.insert(#"aa", 300)
    |> dict.insert(#"bb", 50)
  let filtered = filter_above_threshold(d, 100)
  dict.get(filtered, #"aa") == Some(300)
}

use aiken/collection/dict
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

fn merge_registries(a: dict.Dict<ByteArray, Int>, b: dict.Dict<ByteArray, Int>) -> dict.Dict<ByteArray, Int> {
  dict.union(a, b)
}

fn has_all_keys(d: dict.Dict<ByteArray, Int>, keys: List<ByteArray>) -> Bool {
  when keys is {
    [] -> True
    [k, ..rest] -> dict.has_key(d, k) && has_all_keys(d, rest)
  }
}

validator mint_merge_check {
  mint(_redeemer: Data, _policy_id: PolicyId, _self: Transaction) {
    let reg_a = dict.empty |> dict.insert(#"aa", 1)
    let reg_b = dict.empty |> dict.insert(#"bb", 2)
    let merged = merge_registries(reg_a, reg_b)
    has_all_keys(merged, [#"aa", #"bb"]) && dict.size(merged) == 2
  }
}

test merge_registries_combines() {
  let a = dict.empty |> dict.insert(#"01", 10)
  let b = dict.empty |> dict.insert(#"02", 20)
  let m = merge_registries(a, b)
  dict.size(m) == 2
}

test merge_registries_left_bias() {
  let a = dict.empty |> dict.insert(#"01", 999)
  let b = dict.empty |> dict.insert(#"01", 1)
  let m = merge_registries(a, b)
  dict.get(m, #"01") == Some(999)
}

test has_all_keys_true() {
  let d = dict.empty |> dict.insert(#"aa", 1) |> dict.insert(#"bb", 2)
  has_all_keys(d, [#"aa", #"bb"]) == True
}

test has_all_keys_false() {
  let d = dict.empty |> dict.insert(#"aa", 1)
  has_all_keys(d, [#"aa", #"cc"]) == False
}

test has_all_keys_empty_list() {
  has_all_keys(dict.empty, []) == True
}

use aiken/collection/dict
use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

fn double_values(d: dict.Dict<ByteArray, Int>) -> dict.Dict<ByteArray, Int> {
  dict.map(d, fn(_k, v) { v * 2 })
}

fn sum_values(d: dict.Dict<ByteArray, Int>) -> Int {
  dict.foldl(d, 0, fn(_k, v, acc) { acc + v })
}

fn extract_keys(d: dict.Dict<ByteArray, Int>) -> List<ByteArray> {
  dict.keys(d)
}

validator spend_double_values {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let d = dict.empty |> dict.insert(#"aa", 50) |> dict.insert(#"bb", 25)
    let doubled = double_values(d)
    sum_values(doubled) == 150
  }
}

test double_values_basic() {
  let d = dict.empty |> dict.insert(#"aa", 10) |> dict.insert(#"bb", 20)
  let doubled = double_values(d)
  dict.get(doubled, #"aa") == Some(20)
}

test double_values_sum() {
  let d = dict.empty |> dict.insert(#"cc", 5) |> dict.insert(#"dd", 15)
  sum_values(double_values(d)) == 40
}

test extract_keys_count() {
  let d = dict.empty |> dict.insert(#"aa", 1) |> dict.insert(#"bb", 2) |> dict.insert(#"cc", 3)
  list.length(extract_keys(d)) == 3
}

test double_empty() {
  let doubled = double_values(dict.empty)
  dict.size(doubled) == 0
}

