use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}

fn valor_maximo(d: dict.Dict<ByteArray, Int>) -> Int {
  dict.foldl(d, 0, fn(_k, v, acc) { if v > acc { v } else { acc } })
}

fn contiene_clave(d: dict.Dict<ByteArray, Int>, clave: ByteArray) -> Bool {
  dict.has_key(d, clave)
}

validator spend_max_valor {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let d = dict.empty
      |> dict.insert(#"aa", 500_000)
      |> dict.insert(#"bb", 1_000_000)
      |> dict.insert(#"cc", 750_000)
    valor_maximo(d) >= 1_000_000 && contiene_clave(d, #"bb")
  }
}

test valor_maximo_basico() {
  let d = dict.empty
    |> dict.insert(#"01", 3)
    |> dict.insert(#"02", 7)
    |> dict.insert(#"03", 5)
  valor_maximo(d) == 7
}

test valor_maximo_unico() {
  let d = dict.empty |> dict.insert(#"aa", 42)
  valor_maximo(d) == 42
}

test valor_maximo_vacio() {
  valor_maximo(dict.empty) == 0
}

test contiene_clave_verdadero() {
  let d = dict.empty |> dict.insert(#"ab", 1)
  contiene_clave(d, #"ab") == True
}

test contiene_clave_falso() {
  let d = dict.empty |> dict.insert(#"ab", 1)
  contiene_clave(d, #"cd") == False
}

