use aiken/collection/pairs
use cardano/transaction.{Transaction, OutputReference}

fn check_minimum_balance(
  balances: Pairs<ByteArray, Int>,
  policy_id: ByteArray,
  min_amount: Int,
) -> Bool {
  when pairs.get_first(balances, policy_id) is {
    Some(amount) -> amount >= min_amount
    None -> False
  }
}

fn total_balance(balances: Pairs<ByteArray, Int>) -> Int {
  pairs.foldl(balances, 0, fn(_key, value, acc) { acc + value })
}

validator minimum_balance_check {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let balances: Pairs<ByteArray, Int> =
      [Pair(#"aabb", 500), Pair(#"ccdd", 1000), Pair(#"eeff", 250)]
    check_minimum_balance(balances, #"ccdd", 800)
  }
}

test check_minimum_balance_sufficient() {
  let balances: Pairs<ByteArray, Int> =
    [Pair(#"aabb", 500), Pair(#"ccdd", 1000)]
  check_minimum_balance(balances, #"ccdd", 800) == True
}

test check_minimum_balance_insufficient() {
  let balances: Pairs<ByteArray, Int> =
    [Pair(#"aabb", 500), Pair(#"ccdd", 200)]
  check_minimum_balance(balances, #"ccdd", 800) == False
}

test check_minimum_balance_missing_key() {
  let balances: Pairs<ByteArray, Int> =
    [Pair(#"aabb", 500)]
  check_minimum_balance(balances, #"ccdd", 100) == False
}

test total_balance_sums_correctly() {
  let balances: Pairs<ByteArray, Int> =
    [Pair(#"aabb", 500), Pair(#"ccdd", 1000), Pair(#"eeff", 250)]
  total_balance(balances) == 1750
}

test total_balance_empty() {
  let balances: Pairs<ByteArray, Int> = []
  total_balance(balances) == 0
}

