use aiken/collection/list
use aiken/collection/pairs
use cardano/transaction.{Transaction, OutputReference}

fn all_required_keys_present(
  entries: Pairs<ByteArray, Int>,
  required: List<ByteArray>,
) -> Bool {
  list.all(required, fn(k) { pairs.has_key(entries, k) })
}

fn unique_key_count(entries: Pairs<ByteArray, Int>) -> Int {
  let all_keys = pairs.keys(entries)
  list.length(list.unique(all_keys))
}

validator required_keys_validator {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let entries: Pairs<ByteArray, Int> =
      [Pair(#"aa", 1), Pair(#"bb", 2), Pair(#"cc", 3)]
    let required = [#"aa", #"cc"]
    all_required_keys_present(entries, required)
  }
}

test all_required_present() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1), Pair(#"bb", 2), Pair(#"cc", 3)]
  all_required_keys_present(entries, [#"aa", #"bb"]) == True
}

test required_key_missing() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1), Pair(#"bb", 2)]
  all_required_keys_present(entries, [#"aa", #"dd"]) == False
}

test empty_required_always_true() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1)]
  all_required_keys_present(entries, []) == True
}

test unique_key_count_with_duplicates() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1), Pair(#"bb", 2), Pair(#"aa", 3)]
  unique_key_count(entries) == 2
}

test unique_key_count_no_duplicates() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1), Pair(#"bb", 2), Pair(#"cc", 3)]
  unique_key_count(entries) == 3
}

use aiken/collection/list
use aiken/collection/pairs
use cardano/transaction.{Transaction, OutputReference}

fn remove_and_sum(
  entries: Pairs<ByteArray, Int>,
  key_to_remove: ByteArray,
) -> Int {
  let remaining = pairs.delete_first(entries, key_to_remove)
  let vals = pairs.values(remaining)
  list.foldl(vals, 0, fn(v, acc) { acc + v })
}

fn remaining_keys_after_delete(
  entries: Pairs<ByteArray, Int>,
  key_to_remove: ByteArray,
) -> List<ByteArray> {
  let remaining = pairs.delete_first(entries, key_to_remove)
  pairs.keys(remaining)
}

validator delete_first_validator {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let entries: Pairs<ByteArray, Int> =
      [Pair(#"aa", 100), Pair(#"bb", 200), Pair(#"cc", 300)]
    remove_and_sum(entries, #"bb") == 400
  }
}

test remove_middle_key_sum() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 100), Pair(#"bb", 200), Pair(#"cc", 300)]
  remove_and_sum(entries, #"bb") == 400
}

test remove_first_key_sum() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 100), Pair(#"bb", 200), Pair(#"cc", 300)]
  remove_and_sum(entries, #"aa") == 500
}

test delete_first_only_removes_one() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 10), Pair(#"bb", 20), Pair(#"aa", 30)]
  let remaining = pairs.delete_first(entries, #"aa")
  let vals = pairs.values(remaining)
  vals == [20, 30]
}

test remaining_keys_correct() {
  let entries: Pairs<ByteArray, Int> =
    [Pair(#"aa", 1), Pair(#"bb", 2), Pair(#"cc", 3)]
  remaining_keys_after_delete(entries, #"bb") == [#"aa", #"cc"]
}

