use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

fn suma_valores_si_clave_existe(
  entradas: Pairs<ByteArray, Int>,
  clave_requerida: ByteArray,
) -> Int {
  if pairs.has_key(entradas, clave_requerida) {
    pairs.foldl(entradas, 0, fn(_k, v, acc) { acc + v })
  } else {
    0
  }
}

fn maximo_valor(entradas: Pairs<ByteArray, Int>) -> Int {
  pairs.foldl(
    entradas,
    0,
    fn(_k, v, acc) {
      if v > acc {
        v
      } else {
        acc
      }
    },
  )
}

