fn buscar_monto_exacto(montos: List<Int>, objetivo: Int) -> Option<Int> {
  list.find(montos, fn(m) { m == objetivo })
}

fn contar_montos_validos(montos: List<Int>, minimo: Int) -> Int {
  list.count(montos, fn(m) { m >= minimo })
}

fn primer_monto_valido(montos: List<Int>, minimo: Int) -> Bool {
  when list.head(montos) is {
    Some(primero) -> primero >= minimo
    None -> False
  }
}

fn validar_distribucion(montos: List<Int>, monto_requerido: Int, minimo_por_salida: Int, min_salidas_validas: Int) -> Bool {
  let tiene_monto = when buscar_monto_exacto(montos, monto_requerido) is {
    Some(_) -> True
    None -> False
  }
  let suficientes_validos = contar_montos_validos(montos, minimo_por_salida) >= min_salidas_validas
  let primer_ok = primer_monto_valido(montos, minimo_por_salida)
  tiene_monto && suficientes_validos && primer_ok
}

