  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) {
    let montos = [2_000_000, 5_000_000, 1_500_000, 3_000_000]
    validar_distribucion(montos, 5_000_000, 2_000_000, 2)
  }
}

