/// Computes a simple compound amount: principal * (rate_num)^periods / (rate_den)^periods
/// where rate is represented as rate_num/rate_den (e.g., 11/10 for 10% growth)
fn compound_amount(principal: Int, rate_num: Int, rate_den: Int, periods: Int) -> Int {
  let numerator = principal * math.pow(rate_num, periods)
  let denominator = math.pow(rate_den, periods)
  numerator / denominator
