/// Simplifies a ratio by dividing both parts by their GCD
fn simplify_ratio(numerator: Int, denominator: Int) -> (Int, Int) {
  let divisor = math.gcd(numerator, denominator)
  (numerator / divisor, denominator / divisor)
}

/// Checks whether two ratios are equivalent after simplification
fn ratios_equivalent(a_num: Int, a_den: Int, b_num: Int, b_den: Int) -> Bool {
  let (sa_num, sa_den) = simplify_ratio(a_num, a_den)
  let (sb_num, sb_den) = simplify_ratio(b_num, b_den)
  sa_num == sb_num && sa_den == sb_den
}

