/// Build a role byte from individual boolean flags.
/// Bit 7 = admin, Bit 6 = moderator, Bit 5 = editor, Bit 4 = viewer
fn build_role_byte(admin: Bool, moderator: Bool, editor: Bool, viewer: Bool) -> ByteArray {
  let b0 = 0
  let b1 = if admin { b0 + 128 } else { b0 }
  let b2 = if moderator { b1 + 64 } else { b1 }
  let b3 = if editor { b2 + 32 } else { b2 }
  let b4 = if viewer { b3 + 16 } else { b3 }
  bytearray.push(#"", b4)
}

/// Check if the admin bit (bit 0, i.e. MSB of byte) is set
fn is_admin(role_byte: ByteArray) -> Bool {
  bytearray.test_bit(role_byte, 0)
}

/// Check if the viewer bit (bit 4 from MSB, i.e. bit index 3) is set
fn is_viewer(role_byte: ByteArray) -> Bool {
  bytearray.test_bit(role_byte, 3)
}

validator role_check {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let role = build_role_byte(True, False, False, True)
    is_admin(role) && is_viewer(role)
  }
}

