/// Verificar si el usuario tiene los permisos requeridos
fn verificar_permisos(permisos_usuario: ByteArray, mascara_requerida: ByteArray) -> Bool {
  let resultado = bytearray.and_bytes(permisos_usuario, mascara_requerida, False)
  resultado == mascara_requerida
}

/// Revocar permisos específicos usando XOR.
/// Los bits en mascara_revocacion se voltean en los permisos del usuario.
fn revocar_permisos(permisos_usuario: ByteArray, mascara_revocacion: ByteArray) -> ByteArray {
  let invertido = bytearray.xor_bytes(permisos_usuario, mascara_revocacion, False)
  // AND con los permisos originales para solo quitar bits, no agregar
  bytearray.and_bytes(permisos_usuario, invertido, False)
}

