use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

/// Activar una bandera en la posición indicada (0 = MSB del primer byte)
fn activar_bandera(estado: ByteArray, posicion_bit: Int) -> ByteArray {
  let largo = bytearray.length(estado)
  let byte_idx = posicion_bit / 8
  let bit_en_byte = posicion_bit % 8
  let valor_bit = 128 / pow2(bit_en_byte)
  let byte_actual = bytearray.at(estado, byte_idx)
  let nuevo_byte = byte_actual + valor_bit
  // Construir mascara con OR
  let mascara = construir_mascara(largo, byte_idx, valor_bit)
  bytearray.or_bytes(estado, mascara, False)
}

fn pow2(n: Int) -> Int {
  if n <= 0 { 1 } else { 2 * pow2(n - 1) }
}

fn construir_mascara(largo: Int, byte_idx: Int, valor_bit: Int) -> ByteArray {
  do_construir(largo, byte_idx, valor_bit, 0, #"")
}

fn do_construir(largo: Int, byte_idx: Int, valor_bit: Int, idx: Int, acc: ByteArray) -> ByteArray {
  if idx >= largo {
    acc
  } else if idx == byte_idx {
    do_construir(largo, byte_idx, valor_bit, idx + 1, bytearray.concat(acc, bytearray.push(#"", valor_bit)))
  } else {
    do_construir(largo, byte_idx, valor_bit, idx + 1, bytearray.concat(acc, #"00"))
  }
}

/// Verificar si una bandera está activa
fn bandera_activa(estado: ByteArray, posicion_bit: Int) -> Bool {
  bytearray.test_bit(estado, posicion_bit)
}

validator estado_contrato {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let estado = #"00"
    let nuevo = activar_bandera(estado, 0)
    bandera_activa(nuevo, 0)
  }
}

