use aiken/math/rational.{Rational}
use cardano/transaction.{Transaction, OutputReference}

/// Build a rational from numerator and denominator, returning the Rational
fn make_ratio(num: Int, den: Int) -> Rational {
  expect Some(r) = rational.new(num, den)
  r
}

/// Check if actual_price is within tolerance_bps basis points of expected_price
/// Both prices expressed as (numerator, denominator) pairs
fn price_within_threshold(
  actual_num: Int,
  actual_den: Int,
  expected_num: Int,
  expected_den: Int,
  tolerance_bps: Int,
) -> Bool {
  let actual = make_ratio(actual_num, actual_den)
  let expected = make_ratio(expected_num, expected_den)
  // diff = actual - expected
  let diff = rational.sub(actual, expected)
  // We compare |diff_floor| * 10000 <= tolerance_bps * expected_floor
  // For simplicity: diff_numerator * expected_denominator * 10000 vs tolerance * expected_numerator * diff_denominator
  // Use floor-based approximation: |floor(diff * 10000)| <= tolerance_bps * floor(expected)
  let scale = rational.from_int(10_000)
  let scaled_diff = rational.mul(diff, scale)
  let scaled_diff_val = rational.truncate(scaled_diff)
  let abs_diff = if scaled_diff_val < 0 { -scaled_diff_val } else { scaled_diff_val }
  let expected_floor = rational.floor(expected)
  let max_deviation = tolerance_bps * expected_floor
  abs_diff <= max_deviation
}

