use aiken/math/rational.{Rational}
use cardano/transaction.{Transaction, OutputReference}

/// Check that collateral_value / debt_value >= min_ratio_num / min_ratio_den
fn is_collateralized(
  collateral_value: Int,
  debt_value: Int,
  min_ratio_num: Int,
  min_ratio_den: Int,
) -> Bool {
  expect Some(collateral_ratio) = rational.new(collateral_value, debt_value)
  expect Some(min_ratio) = rational.new(min_ratio_num, min_ratio_den)
  // collateral_ratio >= min_ratio  iff  collateral_ratio - min_ratio >= 0
  let diff = rational.sub(collateral_ratio, min_ratio)
  rational.floor(diff) >= 0
}

/// Compute the maximum borrowable amount given collateral and ratio
fn max_borrow(collateral_value: Int, min_ratio_num: Int, min_ratio_den: Int) -> Int {
  // max_debt = collateral_value * min_ratio_den / min_ratio_num
  expect Some(ratio_inverse) = rational.new(min_ratio_den, min_ratio_num)
  let result = rational.mul(rational.from_int(collateral_value), ratio_inverse)
  rational.floor(result)
}

