use aiken/math/rational.{Rational}
use cardano/transaction.{Transaction, OutputReference}

/// Construye un Rational de forma segura
fn safe_ratio(num: Int, den: Int) -> Rational {
  expect Some(r) = rational.new(num, den)
  r
}

/// Verifica que el tipo de cambio (offered / requested) está entre min y max
/// min_num/min_den <= offered/requested <= max_num/max_den
fn exchange_rate_valid(
  offered: Int,
  requested: Int,
  min_num: Int,
  min_den: Int,
  max_num: Int,
  max_den: Int,
) -> Bool {
  let rate = safe_ratio(offered, requested)
  let min_rate = safe_ratio(min_num, min_den)
  let max_rate = safe_ratio(max_num, max_den)
  // rate - min >= 0 AND max - rate >= 0
  let above_min = rational.floor(rational.sub(rate, min_rate)) >= 0
  let below_max = rational.floor(rational.sub(max_rate, rate)) >= 0
  above_min && below_max
}

/// Calcula cuántos tokens se reciben al intercambiar, dado un tipo de cambio
fn tokens_received(amount_in: Int, rate_num: Int, rate_den: Int) -> Int {
  let rate = safe_ratio(rate_num, rate_den)
  let result = rational.mul(rational.from_int(amount_in), rate)
  rational.floor(result)
}

