use aiken/math/rational.{Rational}
use cardano/transaction.{Transaction, OutputReference}

/// Verifica si los votos a favor alcanzan el umbral requerido
/// threshold es threshold_num/threshold_den (ej: 2/3 para supermayoría)
fn quorum_reached(
  votes_for: Int,
  total_votes: Int,
  threshold_num: Int,
  threshold_den: Int,
) -> Bool {
  expect Some(vote_ratio) = rational.new(votes_for, total_votes)
  expect Some(threshold) = rational.new(threshold_num, threshold_den)
  let diff = rational.sub(vote_ratio, threshold)
  // Si el numerador del diff es >= 0 después de floor, aprobado
  rational.floor(rational.mul(diff, rational.from_int(total_votes * threshold_den))) >= 0
}

/// Calcula cuántos votos mínimos se necesitan para alcanzar el umbral (ceil)
fn min_votes_needed(
  total_votes: Int,
  threshold_num: Int,
  threshold_den: Int,
) -> Int {
  expect Some(threshold) = rational.new(threshold_num, threshold_den)
  let needed = rational.mul(rational.from_int(total_votes), threshold)
  rational.ceil(needed)
}

