use aiken/math/rational.{Rational}
use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference}

/// Aplica una tasa de interés una vez: floor(principal * (1 + rate_num/rate_den))
fn apply_interest_once(principal: Int, rate_num: Int, rate_den: Int) -> Int {
  expect Some(rate) = rational.new(rate_num, rate_den)
  let one = rational.from_int(1)
  let multiplier = rational.add(one, rate)
  let result = rational.mul(rational.from_int(principal), multiplier)
  rational.floor(result)
}

/// Aplica interés compuesto n veces de forma iterativa
fn compound_interest(principal: Int, rate_num: Int, rate_den: Int, periods: Int) -> Int {
  let period_list = list.range(1, periods)
  list.foldl(
    period_list,
    principal,
    fn(_i, acc) { apply_interest_once(acc, rate_num, rate_den) },
  )
}

/// Calcula solo el interés ganado (sin el principal)
fn interest_earned(principal: Int, rate_num: Int, rate_den: Int, periods: Int) -> Int {
  compound_interest(principal, rate_num, rate_den, periods) - principal
}

validator compound_calc {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    True
  }
}

