/// Encode as little-endian and verify it matches expected bytes
fn encode_little_endian_check(value: Int, size: Int, expected: ByteArray) -> Bool {
  bytearray.from_int_little_endian(value, size) == expected
}

/// Verify that big-endian and little-endian produce reversed bytes for a 2-byte value
fn endian_reversal_check(value: Int) -> Bool {
  let big = bytearray.from_int_big_endian(value, 2)
  let little = bytearray.from_int_little_endian(value, 2)
  let big_b0 = bytearray.slice(big, 0, 0)
  let big_b1 = bytearray.slice(big, 1, 1)
  let little_b0 = bytearray.slice(little, 0, 0)
  let little_b1 = bytearray.slice(little, 1, 1)
  big_b0 == little_b1 && big_b1 == little_b0
}

/// Round-trip little endian
fn roundtrip_little_endian(value: Int, size: Int) -> Bool {
  let encoded = bytearray.from_int_little_endian(value, size)
  bytearray.to_int_little_endian(encoded) == value
}

validator endian_validator {
  spend(_datum: Option<Data>, redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    expect (value, size, expected): (Int, Int, ByteArray) = redeemer
    encode_little_endian_check(value, size, expected)
  }
}

