  bytearray.slice(data, start, end)
}

/// Validate that a structured bytearray has the expected total length
fn validate_length(data: ByteArray, expected_len: Int) -> Bool {
  bytearray.length(data) == expected_len
}

/// Check if a bytearray field decoded as big-endian integer meets a minimum
fn field_value_at_least(data: ByteArray, start: Int, end: Int, min_value: Int) -> Bool {
  let field = bytearray.slice(data, start, end)
  bytearray.to_int_big_endian(field) >= min_value
}

