    let valid_len = validate_length(structured, 8)
    let version_ok = extract_field(structured, 0, 1) == #"0001"
    let amount_ok = field_value_at_least(structured, 2, 5, 1_000_000)
    valid_len && version_ok && amount_ok
  }
}

