/// Convierte un bytearray de little-endian a big-endian re-codificando el valor
fn little_a_big(datos: ByteArray, tamano: Int) -> ByteArray {
  let valor = bytearray.to_int_little_endian(datos)
  bytearray.from_int_big_endian(valor, tamano)
}

/// Convierte un bytearray de big-endian a little-endian re-codificando el valor
fn big_a_little(datos: ByteArray, tamano: Int) -> ByteArray {
  let valor = bytearray.to_int_big_endian(datos)
  bytearray.from_int_little_endian(valor, tamano)
}

/// Verifica que ambas representaciones decodifican al mismo valor
fn mismo_valor(big: ByteArray, little: ByteArray) -> Bool {
  bytearray.to_int_big_endian(big) == bytearray.to_int_little_endian(little)
}

validator conversion_endian {
