  } else {
    None
  }
}

fn chain_halve(opt: Option<Int>) -> Option<Int> {
  option.and_then(opt, safe_halve)
}

fn double_chain_halve(opt: Option<Int>) -> Option<Int> {
  opt |> option.and_then(safe_halve) |> option.and_then(safe_halve)
}

fn flatten_nested(opt: Option<Option<Int>>) -> Option<Int> {
  option.flatten(opt)
}

