fn is_strictly_greater(left: Int, right: Int) -> Bool {
  int.compare(left, right) == Greater
}

fn comparison_label(left: Int, right: Int) -> String {
  let ord = int.compare(left, right)
  when ord is {
    Less -> string.concat(int.to_string(left), string.concat(@" < ", int.to_string(right)))
    Equal -> string.concat(int.to_string(left), string.concat(@" == ", int.to_string(right)))
    Greater -> string.concat(int.to_string(left), string.concat(@" > ", int.to_string(right)))
  }
}

