use aiken/primitive/string
use aiken/primitive/int
use cardano/transaction.{Transaction, OutputReference}

fn format_lovelace(amount: Int) -> String {
  let ada_str = int.to_string(amount / 1_000_000)
  let remainder = amount % 1_000_000
  let rem_str = int.to_string(remainder)
  string.join([ada_str, rem_str], @".")
}

fn build_receipt(addr_label: String, amount: Int, confirmed: Bool) -> String {
  let status = if confirmed { @"CONFIRMED" } else { @"PENDING" }
  let amount_str = format_lovelace(amount)
  string.join([addr_label, amount_str, status], @" | ")
}

fn is_valid_amount(amount: Int) -> Bool {
  int.compare(amount, 0) == Greater
}

validator receipt_validator {
  spend(datum: Option<Data>, redeemer: String, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect (label, amount, confirmed): (String, Int, Bool) = raw_datum
    and {
      is_valid_amount(amount),
      redeemer == build_receipt(label, amount, confirmed),
    }
  }
}

