fn encode_int_list(values: List<Int>) -> String {
  let str_values = list.map(values, fn(v) { string.from_int(v) })
  string.join(str_values, @"-")
}

fn encoded_byte_length(values: List<Int>) -> Int {
  let encoded = encode_int_list(values)
  let bytes = string.to_bytearray(encoded)
  bytearray.length(bytes)
}

fn has_max_encoded_length(values: List<Int>, max_len: Int) -> Bool {
  let actual = encoded_byte_length(values)
  when int.compare(actual, max_len) is {
    Greater -> False
    _ -> True
  }
}

