/// Combinar dos rangos de tiempo usando hull y verificar que un punto está contenido
fn punto_en_union_de_rangos(l1: Int, u1: Int, l2: Int, u2: Int, punto: Int) -> Bool {
  let rango1 = interval.between(l1, u1)
  let rango2 = interval.between(l2, u2)
  let combinado = interval.hull(rango1, rango2)
  interval.contains(combinado, punto)
}

/// Verificar si un rango incluye completamente a otro
fn rango_incluye_otro(outer_l: Int, outer_u: Int, inner_l: Int, inner_u: Int) -> Bool {
  let externo = interval.between(outer_l, outer_u)
  let interno = interval.between(inner_l, inner_u)
  interval.includes(externo, interno)
}

validator hull_validator {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) {
    let ventana_permitida = interval.between(0, 5000)
    let rango_tx = self.validity_range
    interval.includes(ventana_permitida, rango_tx)
  }
}

