/// Build a constrained window by intersecting after(start) and before(end)
fn constrained_window(start: Int, end: Int) -> Interval {
  let after_start = interval.after(start)
  let before_end = interval.before(end)
  interval.intersection(after_start, before_end)
}

/// Check if a point is within the constrained window
fn is_within_constrained(time: Int, start: Int, end: Int) -> Bool {
  let window = constrained_window(start, end)
  interval.contains(window, time)
}

/// Check if the constrained window is empty (invalid config where start > end)
fn is_window_empty(start: Int, end: Int) -> Bool {
  let window = constrained_window(start, end)
  interval.is_empty(window)
}

