use cardano/transaction.{Transaction, OutputReference}

/// Determinar si dos periodos de gobernanza se solapan
fn periodos_se_solapan(inicio1: Int, fin1: Int, inicio2: Int, fin2: Int) -> Bool {
  let periodo1 = interval.between(inicio1, fin1)
  let periodo2 = interval.between(inicio2, fin2)
  let solapamiento = interval.intersection(periodo1, periodo2)
  !interval.is_empty(solapamiento)
}

/// Verificar si un periodo está completamente contenido dentro de otro
fn periodo_contenido(ext_inicio: Int, ext_fin: Int, int_inicio: Int, int_fin: Int) -> Bool {
  let externo = interval.between(ext_inicio, ext_fin)
  let interno = interval.between(int_inicio, int_fin)
  interval.includes(externo, interno)
}

/// Obtener el rango combinado de dos periodos
fn rango_total(inicio1: Int, fin1: Int, inicio2: Int, fin2: Int) -> Interval {
  let periodo1 = interval.between(inicio1, fin1)
  let periodo2 = interval.between(inicio2, fin2)
  interval.hull(periodo1, periodo2)
