use aiken/interval.{Interval}
use cardano/transaction.{Transaction, OutputReference}

/// Determinar en qué fase se encuentra un momento dado (0 = ninguna, 1, 2, 3)
fn obtener_fase(tiempo: Int, fase1_fin: Int, fase2_fin: Int, fase3_fin: Int) -> Int {
  let fase1 = interval.before(fase1_fin)
  let fase2 = interval.between(fase1_fin, fase2_fin)
  let fase3 = interval.between(fase2_fin, fase3_fin)
  if interval.contains(fase1, tiempo) {
    1
  } else if interval.contains(fase2, tiempo) {
    2
  } else if interval.contains(fase3, tiempo) {
    3
  } else {
    0
  }
}

/// Verificar si un rango de tiempo cae completamente dentro de una fase
fn rango_en_fase(inicio: Int, fin: Int, fase_inicio: Int, fase_fin: Int) -> Bool {
  let rango_tx = interval.between(inicio, fin)
  let rango_fase = interval.between(fase_inicio, fase_fin)
  interval.includes(rango_fase, rango_tx)
}

/// Verificar que ya pasó una fase (el rango está enteramente después del fin de la fase)
fn fase_ya_paso(inicio_rango: Int, fin_rango: Int, fase_fin: Int) -> Bool {
  let rango = interval.between(inicio_rango, fin_rango)
  interval.is_entirely_after(rango, fase_fin)
}

validator sistema_fases {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, self: Transaction) {
    let fase2_inicio = 1000
    let fase2_fin = 2000
    let rango_fase2 = interval.between(fase2_inicio, fase2_fin)
    let tx_range = self.validity_range
    interval.includes(rango_fase2, tx_range)
  }
}

