fn contar_claves_unicas(entradas: Pairs<ByteArray, Int>) -> Int {
  let todas_las_claves = pairs.keys(entradas)
  list.foldl(
    todas_las_claves,
    [],
    fn(clave, acumulador) {
      if list.has(acumulador, clave) {
        acumulador
      } else {
        [clave, ..acumulador]
      }
    },
  )
    |> list.length()
}

