/// Simplifies a ratio by dividing both numerator and denominator by their GCD
fn simplify_ratio(numerator: Int, denominator: Int) -> (Int, Int) {
  let divisor = math.gcd(numerator, denominator)
  (numerator / divisor, denominator / divisor)
}

/// Checks if a ratio simplifies to the expected simplified form
fn ratio_matches(num: Int, den: Int, expected_num: Int, expected_den: Int) -> Bool {
  let (sn, sd) = simplify_ratio(num, den)
  sn == expected_num && sd == expected_den
}

