/// Computes the absolute deviation between actual and expected price
fn price_deviation(actual: Int, expected: Int) -> Int {
  math.abs(actual - expected)
}

/// Computes a penalty fee: the greater of the deviation or a minimum fee
fn penalty_fee(actual: Int, expected: Int, min_fee: Int) -> Int {
  math.max(price_deviation(actual, expected), min_fee)
}

/// Checks if the penalty fee is below a maximum allowed penalty
fn is_penalty_acceptable(actual: Int, expected: Int, min_fee: Int, max_penalty: Int) -> Bool {
  penalty_fee(actual, expected, min_fee) <= max_penalty
}

