/// Calcula el máximo común divisor de dos cantidades para simplificar la proporción
fn simplificar_proporcion(a: Int, b: Int) -> (Int, Int) {
  let g = math.gcd(math.abs(a), math.abs(b))
  (a / g, b / g)
}

/// Verifica que la proporción tesorería:comunidad es exactamente la esperada
fn proporcion_correcta(tesoreria: Int, comunidad: Int, exp_t: Int, exp_c: Int) -> Bool {
  let (st, sc) = simplificar_proporcion(tesoreria, comunidad)
  st == exp_t && sc == exp_c
}

/// Calcula la distribución de un total según una proporción
fn distribuir(total: Int, parte: Int, partes_totales: Int) -> Int {
  total * parte / partes_totales
}

