use aiken/math
use cardano/transaction.{Transaction, OutputReference}

/// Calcula el factor de crecimiento como rate^periodos (interés compuesto simplificado con enteros)
fn factor_crecimiento(tasa_base: Int, periodos: Int) -> Int {
  math.pow(tasa_base, periodos)
}

/// Calcula el monto final: principal * tasa^periodos / escala^periodos
fn monto_final(principal: Int, tasa_base: Int, periodos: Int, escala: Int) -> Int {
  let factor = factor_crecimiento(tasa_base, periodos)
  let divisor = math.pow(escala, periodos)
  principal * factor / divisor
}

/// Estima cuántos periodos se necesitan para que el principal se duplique con el log
