use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

/// Check if all required permission bits are set in the user's permission mask
fn has_all_permissions(user_mask: ByteArray, required_mask: ByteArray) -> Bool {
  let result = bytearray.and_bytes(user_mask, required_mask, False)
  result == required_mask
}

/// Count how many permission bytes are fully granted (all bits set after AND)
fn count_full_permission_bytes(user_mask: ByteArray, required_mask: ByteArray) -> Int {
  let result = bytearray.and_bytes(user_mask, required_mask, False)
  let len = bytearray.length(result)
  count_full_bytes_loop(result, required_mask, 0, len, 0)
}

fn count_full_bytes_loop(result: ByteArray, required: ByteArray, idx: Int, len: Int, acc: Int) -> Int {
  if idx >= len {
    acc
  } else {
    let r_byte = bytearray.at(result, idx)
    let q_byte = bytearray.at(required, idx)
    if r_byte == q_byte && q_byte > 0 {
      count_full_bytes_loop(result, required, idx + 1, len, acc + 1)
    } else {
      count_full_bytes_loop(result, required, idx + 1, len, acc)
    }
  }
}

validator permission_check {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw) = datum
    expect (user_mask, required_mask): (ByteArray, ByteArray) = raw
    has_all_permissions(user_mask, required_mask)
  }
}

