/// Compute which bits differ between old and new state
fn changed_bits(old_state: ByteArray, new_state: ByteArray) -> ByteArray {
  bytearray.xor_bytes(old_state, new_state, False)
}

/// Check that only allowed bits were changed
fn only_allowed_changes(old_state: ByteArray, new_state: ByteArray, allowed_mask: ByteArray) -> Bool {
  let diff = changed_bits(old_state, new_state)
  let overflow = bytearray.and_bytes(diff, bytearray.xor_bytes(allowed_mask, #"ff", False), False)
  overflow == #"00"
}

/// Check if no bits changed at all
fn no_changes(old_state: ByteArray, new_state: ByteArray) -> Bool {
  let diff = changed_bits(old_state, new_state)
  diff == #"00"
}

