/// Check if a specific feature flag is enabled. Bit 0 is MSB of first byte.
fn is_feature_enabled(flags: ByteArray, feature_bit: Int) -> Bool {
  bytearray.test_bit(flags, feature_bit)
}

/// Check that all specified feature bits are enabled
fn all_features_enabled(flags: ByteArray, feature_bits: List<Int>) -> Bool {
  when feature_bits is {
    [] -> True
    [bit, ..rest] ->
      if bytearray.test_bit(flags, bit) {
        all_features_enabled(flags, rest)
      } else {
        False
      }
  }
}

/// Check that at least one of the specified bits is set
fn any_feature_enabled(flags: ByteArray, feature_bits: List<Int>) -> Bool {
  when feature_bits is {
    [] -> False
    [bit, ..rest] ->
      if bytearray.test_bit(flags, bit) {
        True
      } else {
        any_feature_enabled(flags, rest)
      }
  }
}

