use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

/// Construir una máscara de permisos empujando bytes uno a uno
fn build_permission_mask(admin: Bool, writer: Bool, reader: Bool) -> ByteArray {
  let admin_byte = if admin { 0x80 } else { 0x00 }
  let writer_byte = if writer { 0x40 } else { 0x00 }
  let reader_byte = if reader { 0x20 } else { 0x00 }
  let combined = admin_byte + writer_byte + reader_byte
  bytearray.push(#"", combined)
}

/// Verificar que el usuario tiene al menos los permisos de la máscara requerida
fn verify_permission(user_flags: ByteArray, required: ByteArray) -> Bool {
  let result = bytearray.and_bytes(user_flags, required, False)
  result == required
}

/// Construir máscara y verificar permisos en un solo paso
fn check_user_access(user_flags: ByteArray, needs_admin: Bool, needs_writer: Bool, needs_reader: Bool) -> Bool {
  let required = build_permission_mask(needs_admin, needs_writer, needs_reader)
  verify_permission(user_flags, required)
}

validator control_acceso {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw) = datum
    expect (user_flags, needs_admin, needs_writer, needs_reader): (ByteArray, Bool, Bool, Bool) = raw
    check_user_access(user_flags, needs_admin, needs_writer, needs_reader)
  }
}

