/// Generar una huella digital combinando dos identificadores con XOR
fn fingerprint(id_a: ByteArray, id_b: ByteArray) -> ByteArray {
  bytearray.xor_bytes(id_a, id_b, False)
}

/// Verificar que la huella digital esperada coincide con la calculada
fn verify_fingerprint(id_a: ByteArray, id_b: ByteArray, expected: ByteArray) -> Bool {
  fingerprint(id_a, id_b) == expected
}

/// Verificar que la huella no es todo ceros (los ids deben ser diferentes)
fn ids_are_different(id_a: ByteArray, id_b: ByteArray) -> Bool {
  let fp = fingerprint(id_a, id_b)
  let zero_mask = bytearray.foldl(fp, 0, fn(byte, acc) { acc + byte })
  zero_mask > 0
}

