/// Calculate fee as floor(amount * fee_numerator / fee_denominator)
fn calculate_fee(amount: Int, fee_num: Int, fee_den: Int) -> Int {
  expect Some(fee_rate) = rational.new(fee_num, fee_den)
  let amount_r = rational.from_int(amount)
  let fee_r = rational.mul(amount_r, fee_rate)
  rational.floor(fee_r)
}

/// Check that the paid fee is at least the required fee
fn fee_is_sufficient(amount: Int, fee_num: Int, fee_den: Int, paid_fee: Int) -> Bool {
  let required = calculate_fee(amount, fee_num, fee_den)
  paid_fee >= required
}

