use aiken/math/rational.{Rational}
use cardano/transaction.{Transaction, OutputReference}

/// Build a rational from two ints safely
fn make_ratio(num: Int, den: Int) -> Rational {
  expect Some(r) = rational.new(num, den)
  r
}

/// Check if actual_price is within tolerance_bps (basis points) of expected_price
/// i.e. |actual - expected| * 10000 <= expected * tolerance_bps
fn price_within_threshold(
  actual_num: Int,
  actual_den: Int,
  expected_num: Int,
  expected_den: Int,
  tolerance_bps: Int,
) -> Bool {
  let actual = make_ratio(actual_num, actual_den)
  let expected = make_ratio(expected_num, expected_den)
  let diff = rational.sub(actual, expected)
  let diff_abs_num = if rational.numerator(diff) < 0 {
    -rational.numerator(diff)
  } else {
    rational.numerator(diff)
  }
  let diff_abs_den = rational.denominator(diff)
  let diff_abs = make_ratio(diff_abs_num, diff_abs_den)
  let tolerance_ratio = make_ratio(tolerance_bps, 10000)
  let max_deviation = rational.mul(expected, tolerance_ratio)
  let diff_scaled = rational.floor(rational.mul(diff_abs, rational.from_int(10000)))
  let max_scaled = rational.floor(rational.mul(max_deviation, rational.from_int(10000)))
  diff_scaled <= max_scaled
}

validator oracle_threshold {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    price_within_threshold(101, 100, 1, 1, 500)
  }
}

