/// Verifica si colateral/deuda >= umbral_num/umbral_den
fn colateral_suficiente(
  colateral: Int,
  deuda: Int,
  umbral_num: Int,
  umbral_den: Int,
) -> Bool {
  expect Some(ratio_colateral) = rational.new(colateral, deuda)
  expect Some(umbral) = rational.new(umbral_num, umbral_den)
  // ratio_colateral - umbral >= 0 means colateral is sufficient
  let diferencia = rational.sub(ratio_colateral, umbral)
  rational.numerator(diferencia) >= 0
}

/// Calcula cuánto colateral mínimo se necesita: ceil(deuda * umbral_num / umbral_den)
fn colateral_minimo(deuda: Int, umbral_num: Int, umbral_den: Int) -> Int {
  expect Some(umbral) = rational.new(umbral_num, umbral_den)
  let deuda_r = rational.from_int(deuda)
  let minimo = rational.mul(deuda_r, umbral)
  rational.ceil(minimo)
}

