use aiken/math/rational.{Rational}
use aiken/collection/list
use cardano/transaction.{OutputReference, Transaction}

/// Calcula VWAP: sum(precio_i * volumen_i) / sum(volumen_i)
/// Recibe lista de pares (precio, volumen) y retorna floor del resultado
fn calcular_vwap(trades: List<(Int, Int)>) -> Int {
  let sum_pv = list.foldl(
    trades,
    rational.from_int(0),
    fn(trade, acc) {
      let (precio, volumen) = trade
      let pv = rational.mul(rational.from_int(precio), rational.from_int(volumen))
      rational.add(acc, pv)
    },
  )
  let sum_vol = list.foldl(
    trades,
    0,
    fn(trade, acc) {
      let (_precio, volumen) = trade
      acc + volumen
    },
  )
  expect Some(divisor) = rational.new(1, sum_vol)
  let vwap = rational.mul(sum_pv, divisor)
  rational.floor(vwap)
}

/// Verifica que el VWAP está por encima de un precio mínimo
fn vwap_sobre_minimo(trades: List<(Int, Int)>, precio_minimo: Int) -> Bool {
  calcular_vwap(trades) >= precio_minimo
}

validator vwap_validator {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let trades = [(100, 10), (110, 20), (105, 15)]
    vwap_sobre_minimo(trades, 100)
  }
}

