use aiken/math/rational.{Rational}
use cardano/transaction.{OutputReference, Transaction}

/// Convierte una cantidad usando tipo de cambio rate_num/rate_den, retorna floor
fn convertir(cantidad: Int, tasa_num: Int, tasa_den: Int) -> Int {
  expect Some(tasa) = rational.new(tasa_num, tasa_den)
  let cantidad_r = rational.from_int(cantidad)
  let resultado = rational.mul(cantidad_r, tasa)
  rational.floor(resultado)
}

/// Verifica que el slippage no exceda max_bps puntos base
/// slippage = |esperado - recibido| / esperado <= max_bps / 10000
fn slippage_aceptable(esperado: Int, recibido: Int, max_bps: Int) -> Bool {
  let diff = if recibido > esperado { recibido - esperado } else { esperado - recibido }
  expect Some(ratio_diff) = rational.new(diff, esperado)
  expect Some(limite) = rational.new(max_bps, 10000)
  let resultado = rational.sub(limite, ratio_diff)
  rational.numerator(resultado) >= 0
}

/// Conversión con verificación de slippage
fn swap_con_slippage(
  cantidad: Int,
  tasa_num: Int,
  tasa_den: Int,
  recibido: Int,
  max_slippage_bps: Int,
) -> Bool {
  let esperado = convertir(cantidad, tasa_num, tasa_den)
  slippage_aceptable(esperado, recibido, max_slippage_bps)
}

