/// CIP-68 reference token label prefix: 000643b0
const cip68_reference_label: ByteArray = #"000643b0"

/// Check if an asset name starts with the CIP-68 reference label
fn has_cip68_reference_prefix(asset_name: ByteArray) -> Bool {
  bytearray.starts_with(asset_name, cip68_reference_label)
}

/// Extract the token name part after the 4-byte CIP-68 label
fn extract_token_name(asset_name: ByteArray) -> ByteArray {
  let total_len = bytearray.length(asset_name)
  bytearray.slice(asset_name, 4, total_len - 1)
}

/// Get the label portion (first 4 bytes)
fn extract_label(asset_name: ByteArray) -> ByteArray {
  bytearray.take(asset_name, 4)
}

