/// Codifica un entero en little-endian y compara con el valor esperado
fn codificar_little_endian(valor: Int, tamano: Int, esperado: ByteArray) -> Bool {
  let codificado = bytearray.from_int_little_endian(valor, tamano)
  codificado == esperado
}

/// Verifica ida y vuelta en little-endian
fn ida_y_vuelta_little_endian(valor: Int, tamano: Int) -> Bool {
  let codificado = bytearray.from_int_little_endian(valor, tamano)
  let decodificado = bytearray.to_int_little_endian(codificado)
  decodificado == valor
}

/// Demuestra que big-endian y little-endian producen resultados distintos para valores > 255
fn endians_difieren(valor: Int, tamano: Int) -> Bool {
  let big = bytearray.from_int_big_endian(valor, tamano)
  let little = bytearray.from_int_little_endian(valor, tamano)
  big != little
}

validator verificar_endian {
  spend(datum: Option<Data>, redeemer: Int, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect esperado: ByteArray = raw_datum
    let tamano = bytearray.length(esperado)
    codificar_little_endian(redeemer, tamano, esperado)
  }
}

