/// Divide un bytearray en cabeza (primeros n bytes) y cola (el resto)
fn dividir(datos: ByteArray, n: Int) -> (ByteArray, ByteArray) {
  let cabeza = bytearray.take(datos, n)
  let cola = bytearray.drop(datos, n)
  (cabeza, cola)
}

