const timestamp_size: Int = 8

/// Encode a POSIX timestamp as 8-byte big-endian
fn encode_timestamp(ts: Int) -> ByteArray {
  bytearray.from_int_big_endian(ts, timestamp_size)
}

/// Decode an 8-byte big-endian bytearray back to a timestamp
fn decode_timestamp(raw: ByteArray) -> Int {
  bytearray.to_int_big_endian(raw)
}

/// Check if a timestamp bytearray represents a value within [lower, upper]
fn timestamp_in_range(raw: ByteArray, lower: Int, upper: Int) -> Bool {
  let ts = decode_timestamp(raw)
  ts >= lower && ts <= upper
}

/// Verify the encoded timestamp has exactly the right size
fn valid_timestamp_encoding(ts: Int) -> Bool {
  let encoded = encode_timestamp(ts)
  bytearray.length(encoded) == timestamp_size
}

validator timestamp_validator {
  spend(datum: Option<Data>, redeemer: ByteArray, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect bounds: (Int, Int) = raw_datum
    let (lower, upper) = bounds
    and {
      bytearray.length(redeemer) == timestamp_size,
      timestamp_in_range(redeemer, lower, upper),
    }
  }
}

test encode_decode_round_trip() {
  let ts = 1700000000
  decode_timestamp(encode_timestamp(ts)) == ts
}

