  let raw = encode_timestamp(1700000500)
  timestamp_in_range(raw, 1700000000, 1700001000) == True
}

test timestamp_in_range_out_of_bounds() {
  let raw = encode_timestamp(1700002000)
  timestamp_in_range(raw, 1700000000, 1700001000) == False
}

test valid_encoding_size() {
  valid_timestamp_encoding(1700000000) == True
}

