/// Build a composite key: prefix ++ big-endian(index, 4)
fn build_composite_key(prefix: ByteArray, index: Int) -> ByteArray {
  let index_bytes = bytearray.from_int_big_endian(index, 4)
  bytearray.concat(prefix, index_bytes)
}

/// Verify a composite key starts with the given prefix
fn verify_key_prefix(key: ByteArray, prefix: ByteArray) -> Bool {
  bytearray.starts_with(key, prefix)
}

/// Extract the index from a composite key given the prefix length
fn extract_index(key: ByteArray, prefix_len: Int) -> Int {
  let index_bytes = bytearray.drop(key, prefix_len)
  bytearray.to_int_big_endian(index_bytes)
}

/// Validate total key length is prefix_len + 4
fn valid_key_length(key: ByteArray, prefix_len: Int) -> Bool {
  bytearray.length(key) == prefix_len + 4
}

validator composite_key_check {
  spend(datum: Option<Data>, redeemer: Int, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect (prefix, expected_key): (ByteArray, ByteArray) = raw_datum
    let computed_key = build_composite_key(prefix, redeemer)
    computed_key == expected_key
  }
}

