use aiken/builtin
use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

/// Codifica dos enteros como big-endian del mismo tamaño y compara lexicográficamente
fn comparar_como_bytes(a: Int, b: Int, tamano: Int) -> Ordering {
  let bytes_a = bytearray.from_int_big_endian(a, tamano)
  let bytes_b = bytearray.from_int_big_endian(b, tamano)
  bytearray.compare(bytes_a, bytes_b)
}

/// Verifica que un valor codificado es menor que un límite
fn menor_que_limite(valor_bytes: ByteArray, limite: Int) -> Bool {
  let tamano = bytearray.length(valor_bytes)
  let limite_bytes = bytearray.from_int_big_endian(limite, tamano)
  bytearray.compare(valor_bytes, limite_bytes) == Less
}

/// Verifica que un valor codificado es mayor o igual a un mínimo
fn mayor_o_igual_minimo(valor_bytes: ByteArray, minimo: Int) -> Bool {
  let tamano = bytearray.length(valor_bytes)
  let minimo_bytes = bytearray.from_int_big_endian(minimo, tamano)
  let resultado = bytearray.compare(valor_bytes, minimo_bytes)
  resultado == Greater || resultado == Equal
}

validator comparacion_bytes {
  spend(datum: Option<Data>, redeemer: Int, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect (minimo, maximo): (Int, Int) = raw_datum
    let valor_bytes = bytearray.from_int_big_endian(redeemer, 4)
    and {
      mayor_o_igual_minimo(valor_bytes, minimo),
      menor_que_limite(valor_bytes, maximo),
    }
  }
}

test comparar_menor() {
  comparar_como_bytes(100, 200, 2) == Less
}

test comparar_igual() {
  comparar_como_bytes(500, 500, 4) == Equal
}

test comparar_mayor() {
  comparar_como_bytes(1000, 999, 4) == Greater
}

