  menor_que_limite(v, 100) == False
}

test mayor_o_igual_exacto() {
  let v = bytearray.from_int_big_endian(100, 2)
  mayor_o_igual_minimo(v, 100) == True
}

use aiken/primitive/bytearray
use cardano/transaction.{Transaction, OutputReference}

const prefijo_tamano: Int = 4
const contador_tamano: Int = 4

/// Construye un identificador: take(policy_hash, 4) ++ little_endian(contador, 4)
fn construir_id(policy_hash: ByteArray, contador: Int) -> ByteArray {
  let prefijo = bytearray.take(policy_hash, prefijo_tamano)
  let contador_bytes = bytearray.from_int_little_endian(contador, contador_tamano)
  bytearray.concat(prefijo, contador_bytes)
}

/// Extrae el prefijo de política del identificador
fn extraer_prefijo_politica(id: ByteArray) -> ByteArray {
  bytearray.take(id, prefijo_tamano)
}

/// Extrae el contador del identificador como entero
fn extraer_contador(id: ByteArray) -> Int {
  let contador_bytes = bytearray.drop(id, prefijo_tamano)
  bytearray.to_int_little_endian(contador_bytes)
}

/// Verifica que el id tiene la longitud correcta y empieza con el prefijo esperado
fn id_valido(id: ByteArray, policy_hash: ByteArray) -> Bool {
  let longitud_correcta = bytearray.length(id) == prefijo_tamano + contador_tamano
  let prefijo_esperado = bytearray.take(policy_hash, prefijo_tamano)
  let prefijo_correcto = bytearray.starts_with(id, prefijo_esperado)
  longitud_correcta && prefijo_correcto
}

validator id_unico {
  spend(datum: Option<Data>, redeemer: Int, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw_datum) = datum
    expect (policy_hash, id_esperado): (ByteArray, ByteArray) = raw_datum
    let id_construido = construir_id(policy_hash, redeemer)
    and {
      id_construido == id_esperado,
      id_valido(id_esperado, policy_hash),
    }
  }
}

