  let policy = #"aabbccddee"
  let id = construir_id(policy, 1)
  id == #"aabbccdd01000000"
}

test extraer_prefijo() {
  let id = #"aabbccdd05000000"
  extraer_prefijo_politica(id) == #"aabbccdd"
}

test extraer_contador_correcto() {
  let id = #"aabbccdde8030000"
  extraer_contador(id) == 1000
}

test id_valido_correcto() {
  let policy = #"aabbccddeeff"
  let id = construir_id(policy, 42)
  id_valido(id, policy) == True
}

test id_valido_prefijo_incorrecto() {
  let policy = #"11223344eeff"
