use aiken/option
use cardano/transaction.{Transaction, OutputReference}

fn safe_halve(val: Int) -> Option<Int> {
  if val % 2 == 0 {
    Some(val / 2)
  } else {
    None
  }
}

fn chain_halve(input: Option<Int>) -> Option<Int> {
  option.and_then(input, safe_halve)
}

fn double_halve(input: Option<Int>) -> Option<Int> {
  input
    |> option.and_then(safe_halve)
    |> option.and_then(safe_halve)
}

validator chained_optional {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw): Option<Data> = datum
    expect d: Int = raw
    let result = chain_halve(Some(d))
    option.is_some(result)
  }
}

test chain_halve_even() {
  chain_halve(Some(42)) == Some(21)
}

test chain_halve_odd() {
  chain_halve(Some(7)) == None
}

test chain_halve_none() {
  chain_halve(None) == None
}

test double_halve_divisible_by_4() {
  double_halve(Some(100)) == Some(25)
}

test double_halve_not_divisible_by_4() {
  double_halve(Some(42)) == None
}

use aiken/option
use cardano/transaction.{Transaction, OutputReference}

fn with_default(val: Option<Int>, default: Int) -> Int {
  option.or_else(val, default)
}

fn threshold_check(val: Option<Int>, threshold: Int, default: Int) -> Bool {
  let effective = with_default(val, default)
  effective >= threshold
}

validator default_fallback {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let fallback_value = 100
    let min_threshold = 50
    when datum is {
      Some(raw) -> {
        expect d: Int = raw
        threshold_check(Some(d), min_threshold, fallback_value)
      }
      None -> threshold_check(None, min_threshold, fallback_value)
    }
  }
}

test or_else_some() {
  with_default(Some(42), 0) == 42
}

test or_else_none() {
  with_default(None, 99) == 99
}

test threshold_with_value_above() {
  threshold_check(Some(60), 50, 100) == True
}

test threshold_with_value_below() {
  threshold_check(Some(30), 50, 100) == False
}

test threshold_with_none_uses_default() {
  threshold_check(None, 50, 100) == True
}

