fn combinar_opciones(a: Option<Int>, b: Option<Int>) -> Option<Int> {
  option.map2(a, b, fn(x, y) { x * y })
}

fn supera_umbral(a: Option<Int>, b: Option<Int>, umbral: Int) -> Bool {
  let resultado = combinar_opciones(a, b)
  when resultado is {
    Some(val) -> val >= umbral
    None -> False
  }
}

fn sumar_opciones(a: Option<Int>, b: Option<Int>) -> Option<Int> {
  option.map2(a, b, fn(x, y) { x + y })
}

