use aiken/option
use cardano/transaction.{Transaction, OutputReference}

fn buscar_en_fuente_primaria(clave: Int) -> Option<Int> {
  if clave == 1 {
    Some(1000)
  } else {
    None
  }
}

fn buscar_en_fuente_secundaria(clave: Int) -> Option<Int> {
  if clave == 2 {
    Some(2000)
  } else {
    None
  }
}

fn buscar_con_prioridad(clave: Int) -> Option<Int> {
  option.choice(
    [buscar_en_fuente_primaria(clave), buscar_en_fuente_secundaria(clave)],
  )
}

fn transformar_y_validar(clave: Int, minimo: Int) -> Bool {
  let encontrado = buscar_con_prioridad(clave)
  let transformado = option.map(encontrado, fn(v) { v + 500 })
  let verificado =
    option.and_then(
      transformado,
      fn(v) {
        if v >= minimo {
          Some(v)
        } else {
          None
        }
      },
    )
  let final_val = option.or_else(verificado, 0)
  final_val > 0
}

validator cadena_validador {
  spend(datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    expect Some(raw): Option<Data> = datum
    expect clave: Int = raw
    transformar_y_validar(clave, 1000)
  }
}

