use aiken/interval.{Interval}
use cardano/transaction.{Transaction, OutputReference}

/// Checks if a slot number falls within a given epoch defined by start and end slots
fn is_within_epoch(slot: Int, epoch_start: Int, epoch_end: Int) -> Bool {
  let epoch_range = interval.between(epoch_start, epoch_end)
  interval.contains(epoch_range, slot)
}

/// Checks if two epoch ranges overlap by testing if their intersection is non-empty
fn epochs_overlap(start1: Int, end1: Int, start2: Int, end2: Int) -> Bool {
  let range1 = interval.between(start1, end1)
  let range2 = interval.between(start2, end2)
  let common = interval.intersection(range1, range2)
  !interval.is_empty(common)
}

