  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let epoch_start = 432000
    let epoch_end = 864000
    let current_slot = 500000
    is_within_epoch(current_slot, epoch_start, epoch_end)
  }
}

