use aiken/interval.{Interval}
use cardano/transaction.{Transaction, OutputReference}

/// Computes the hull (smallest enclosing interval) of two time windows
/// and checks if a point is within the combined range
fn is_in_combined_schedule(point: Int, start1: Int, end1: Int, start2: Int, end2: Int) -> Bool {
  let window1 = interval.between(start1, end1)
  let window2 = interval.between(start2, end2)
  let combined = interval.hull(window1, window2)
  interval.contains(combined, point)
}

/// Checks if one schedule window fully includes another
fn schedule_includes(outer_start: Int, outer_end: Int, inner_start: Int, inner_end: Int) -> Bool {
  let outer = interval.between(outer_start, outer_end)
  let inner = interval.between(inner_start, inner_end)
  interval.includes(outer, inner)
}

validator schedule_hull_validator {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    is_in_combined_schedule(25, 10, 20, 30, 40)
  }
}

