/// Determina si dos ventanas de tiempo tienen intersección no vacía (conflicto)
fn hay_conflicto_horario(inicio1: Int, fin1: Int, inicio2: Int, fin2: Int) -> Bool {
  let ventana1 = interval.between(inicio1, fin1)
  let ventana2 = interval.between(inicio2, fin2)
  let comun = interval.intersection(ventana1, ventana2)
  !interval.is_empty(comun)
}

/// Verifica que un tiempo propuesto esté dentro de la intersección de dos ventanas
fn en_interseccion(tiempo: Int, inicio1: Int, fin1: Int, inicio2: Int, fin2: Int) -> Bool {
  let ventana1 = interval.between(inicio1, fin1)
  let ventana2 = interval.between(inicio2, fin2)
  let comun = interval.intersection(ventana1, ventana2)
  interval.contains(comun, tiempo)
}

