use aiken/interval.{Interval}
use cardano/transaction.{Transaction, OutputReference}
use cardano/assets.{PolicyId}

/// Determina en qué fase se encuentra un proyecto dado el tiempo actual
/// Retorna 1 para inversión, 2 para activa, 3 para retiro, 0 para fuera de rango
fn fase_proyecto(tiempo: Int, fin_inversion: Int, fin_activa: Int, fin_retiro: Int) -> Int {
  let fase_inversion = interval.before(fin_inversion)
  let fase_activa = interval.between(fin_inversion, fin_activa)
  let fase_retiro = interval.between(fin_activa, fin_retiro)
  if interval.contains(fase_inversion, tiempo) {
    1
  } else if interval.contains(fase_activa, tiempo) {
    2
  } else if interval.contains(fase_retiro, tiempo) {
    3
  } else {
    0
  }
}

/// Verifica que la fase de inversión y la fase activa no se solapen
fn fases_validas(fin_inversion: Int, fin_activa: Int, fin_retiro: Int) -> Bool {
  let inversiones = interval.before(fin_inversion)
  let activa = interval.entirely_between(fin_inversion, fin_activa)
  let retiro = interval.entirely_between(fin_activa, fin_retiro)
  let inv_activa = interval.intersection(inversiones, activa)
  let activa_retiro = interval.intersection(activa, retiro)
  interval.is_empty(inv_activa) && interval.is_empty(activa_retiro)
}

validator proyecto_fases {
  mint(_redeemer: Data, _policy_id: PolicyId, _self: Transaction) {
    let tiempo_actual = 500
    let fase = fase_proyecto(tiempo_actual, 1000, 2000, 3000)
    fase == 1
  }
}

