fn sort_ascending(xs: List<Int>) -> List<Int> {
  list.sort(xs, int.compare)
}

fn is_sorted(xs: List<Int>) -> Bool {
  when xs is {
    [] -> True
    [_] -> True
    [a, b, ..rest] ->
      if a <= b {
        is_sorted([b, ..rest])
      } else {
        False
      }
  }
}

validator sort_validator {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let unsorted = [5, 3, 8, 1, 9, 2]
    let sorted = sort_ascending(unsorted)
    is_sorted(sorted)
  }
}

