use aiken/collection/list
use aiken/primitive/int
use cardano/transaction.{Transaction, OutputReference}

fn take_below_threshold(xs: List<Int>, threshold: Int) -> List<Int> {
  let sorted = list.sort(xs, int.compare)
  list.take_while(sorted, fn(x) { x < threshold })
}

fn drop_below_threshold(xs: List<Int>, threshold: Int) -> List<Int> {
  let sorted = list.sort(xs, int.compare)
  list.drop_while(sorted, fn(x) { x < threshold })
}

validator threshold_split {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let values = [10, 50, 30, 20, 40, 60]
    let below = take_below_threshold(values, 35)
    let at_or_above = drop_below_threshold(values, 35)
    list.length(below) == 3 && list.length(at_or_above) == 3
  }
}

test take_below_threshold_basic() {
  take_below_threshold([5, 3, 8, 1, 9, 2], 5) == [1, 2, 3]
}

test drop_below_threshold_basic() {
  drop_below_threshold([5, 3, 8, 1, 9, 2], 5) == [5, 8, 9]
}

test take_below_threshold_all() {
  take_below_threshold([1, 2, 3], 100) == [1, 2, 3]
}

test take_below_threshold_none() {
  take_below_threshold([10, 20, 30], 5) == []
}

test drop_below_threshold_all_dropped() {
  drop_below_threshold([1, 2, 3], 100) == []
}

test split_preserves_total_length() {
  let xs = [3, 1, 4, 1, 5, 9]
  let a = take_below_threshold(xs, 4)
  let b = drop_below_threshold(xs, 4)
  list.length(a) + list.length(b) == 6
}

