use aiken/collection/list
use aiken/primitive/int
use cardano/transaction.{Transaction, OutputReference}

fn generar_rango(inicio: Int, fin: Int) -> List<Int> {
  list.range(inicio, fin)
}

fn repetir_valor(valor: Int, veces: Int) -> List<Int> {
  list.repeat(valor, veces)
}

fn construir_patron(n: Int) -> List<Int> {
  let rango = generar_rango(1, n)
  let ceros = repetir_valor(0, n)
  list.concat(rango, ceros)
}

fn patron_ordenado(n: Int) -> List<Int> {
  let patron = construir_patron(n)
  list.sort(patron, int.compare)
}

validator patron_datos {
  spend(_datum: Option<Data>, _redeemer: Data, _own_ref: OutputReference, _self: Transaction) {
    let patron = construir_patron(3)
    list.length(patron) == 6
  }
}

test generar_rango_basico() {
  generar_rango(1, 5) == [1, 2, 3, 4, 5]
}

test generar_rango_un_elemento() {
  generar_rango(3, 3) == [3]
}

test repetir_valor_basico() {
  repetir_valor(7, 3) == [7, 7, 7]
}

test repetir_valor_cero_veces() {
  repetir_valor(7, 0) == []
}

test construir_patron_tres() {
  construir_patron(3) == [1, 2, 3, 0, 0, 0]
}

test patron_ordenado_tres() {
  patron_ordenado(3) == [0, 0, 0, 1, 2, 3]
}

test construir_patron_longitud() {
  list.length(construir_patron(5)) == 10
}

